SELECT 
FROM product

    status = 1

        AND (name LIKE CONCAT('%', #{keyword}, '%')
        OR description LIKE CONCAT('%', #{keyword}, '%'))


        AND category_id IN (
        SELECT id FROM product_category
        WHERE id = #{categoryId} OR parent_id = #{categoryId}
        )


        AND is_hot = #{isHot}


        AND is_new = #{isNew}


ORDER BY is_hot DESC, is_new DESC, sales DESC, id DESC
LIMIT #{offset}, #{limit}

