FROM product


        AND name LIKE CONCAT('%', #{keyword}, '%')


        AND category_id = #{categoryId}


        AND status = #{status}


ORDER BY id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM product


        AND name LIKE CONCAT('%', #{keyword}, '%')


        AND category_id = #{categoryId}


